const item = $input.first().json;
const apiId = (item.api_id || item.input || '').trim();

if (!apiId) {
  return [{
    json: {
      erro: `Nenhum api_id recebido. Campos: ${JSON.stringify(Object.keys(item))}. IDs válidos: não disponível.`
    }
  }];
}

// Lê o catálogo que veio como parâmetro do workflow pai
let catalogo = {};
try {
  catalogo = JSON.parse(item.catalogo_mapa);
} catch (e) {
  return [{
    json: {
      erro: `Erro ao ler catalogo_mapa: ${e.message}. Valor recebido: ${item.catalogo_mapa}`
    }
  }];
}

const url = catalogo[apiId];

if (!url) {
  return [{
    json: {
      erro: `api_id "${apiId}" não encontrado. IDs válidos: ${Object.keys(catalogo).join(", ")}`
    }
  }];
}

return [{ json: { url, api_id: apiId } }];

// ============================================================
// Parser WSDL v2 — Extração completa com herança e hierarquia
// Recebe o XML bruto do HTTP Request e o api_id do nó anterior
// ============================================================

const rawData = $input.first().json.data || $input.first().json.body || '';
const apiId = $('Resolver URL').first().json.api_id || 'desconhecido';

if (!rawData || typeof rawData !== 'string' || rawData.trim().length === 0) {
  return [{
    json: {
      api_id: apiId,
      conteudo: `Erro: Não foi possível obter o conteúdo WSDL para "${apiId}".`
    }
  }];
}

const xml = rawData.trim();

// ── Helpers ──

function stripNs(val) {
  if (!val) return '';
  return val.includes(':') ? val.split(':').pop() : val;
}

function getAttr(tag, attr) {
  const m = tag.match(new RegExp(`${attr}\\s*=\\s*["']([^"']*)["']`, 'i'));
  return m ? m[1] : null;
}

// ── 1. Extrair TODOS os complexType nomeados (com herança) ──

const namedTypes = {};

// Regex que pega <complexType name="...">...</complexType> (com ou sem namespace)
const ctRegex = /<[\w:]*complexType\s+[^>]*?name\s*=\s*["']([^"']*)["'][^>]*?>([\s\S]*?)<\/[\w:]*complexType>/gi;
let ctMatch;
while ((ctMatch = ctRegex.exec(xml)) !== null) {
  const typeName = ctMatch[1];
  const body = ctMatch[2];

  // Detectar herança: <extension base="...">
  const extMatch = body.match(/extension\s+base\s*=\s*["']([^"']*)["']/i);
  const baseType = extMatch ? stripNs(extMatch[1]) : null;

  // Extrair elementos filhos diretos
  const campos = [];
  const elRegex = /<[\w:]*element\s+[^>]*?name\s*=\s*["']([^"']*)["'][^>]*?\/?>/gi;
  let elMatch;
  while ((elMatch = elRegex.exec(body)) !== null) {
    const nome = elMatch[1];
    const tag = elMatch[0];
    const tipo = getAttr(tag, 'type');
    const nillable = getAttr(tag, 'nillable') === 'true';
    const minOccurs = getAttr(tag, 'minOccurs');
    const maxOccurs = getAttr(tag, 'maxOccurs');

    const tipoLimpo = tipo ? stripNs(tipo) : 'any';
    const obrigatorio = minOccurs !== '0';
    const lista = maxOccurs === 'unbounded';

    campos.push({ nome, tipo: tipoLimpo, obrigatorio, nillable, lista });
  }

  namedTypes[typeName] = { baseType, campos };
}

// ── 2. Extrair elementos raiz (operações de request/response) com inline types ──

const rootElements = {};
const rootElRegex = /<[\w:]*element\s+[^>]*?name\s*=\s*["']([^"']*)["'][^>]*?>([\s\S]*?)<\/[\w:]*element>/gi;
let rootMatch;
while ((rootMatch = rootElRegex.exec(xml)) !== null) {
  const elName = rootMatch[1];
  const body = rootMatch[2];

  // Só pegar elementos raiz que contêm complexType inline (são os wrappers de operação)
  if (!body.match(/complexType/i)) continue;

  const campos = [];
  const innerElRegex = /<[\w:]*element\s+[^>]*?name\s*=\s*["']([^"']*)["'][^>]*?\/?>/gi;
  let innerMatch;
  while ((innerMatch = innerElRegex.exec(body)) !== null) {
    const nome = innerMatch[1];
    const tag = innerMatch[0];
    const tipo = getAttr(tag, 'type');
    const minOccurs = getAttr(tag, 'minOccurs');
    const nillable = getAttr(tag, 'nillable') === 'true';

    campos.push({
      nome,
      tipo: tipo ? stripNs(tipo) : 'any',
      obrigatorio: minOccurs !== '0',
      nillable
    });
  }

  if (campos.length > 0) {
    rootElements[elName] = campos;
  }
}

// ── 3. Resolver herança recursivamente ──

function resolveFields(typeName, visited) {
  if (!typeName || !namedTypes[typeName]) return [];
  if (!visited) visited = new Set();
  if (visited.has(typeName)) return []; // evitar loop
  visited.add(typeName);

  const t = namedTypes[typeName];
  const inherited = t.baseType ? resolveFields(t.baseType, visited) : [];
  return [...inherited, ...t.campos];
}

// ── 4. Expandir tipo completo com profundidade (até 3 níveis) ──

function expandType(typeName, depth, visited) {
  if (depth > 8) return '(ver detalhes do tipo ' + typeName + ')';
  if (!visited) visited = new Set();
  if (visited.has(typeName)) return '(referência circular a ' + typeName + ')';
  visited.add(typeName);

  const allFields = resolveFields(typeName, new Set());
  if (allFields.length === 0) return '(sem campos)';

  const indent = '    '.repeat(depth);
  let result = '';

  for (const f of allFields) {
    const obrig = f.obrigatorio ? ' [OBRIGATÓRIO]' : ' [opcional]';
    const lista = f.lista ? ' [LISTA]' : '';

    // Verificar se o tipo é primitivo
    const primitivos = ['string', 'int', 'long', 'boolean', 'dateTime', 'decimal', 'double', 'float', 'short', 'byte', 'any', 'anyType'];
    const isPrimitivo = primitivos.includes(f.tipo);

    result += `${indent}- ${f.nome}: ${f.tipo}${obrig}${lista}\n`;

    // Se não é primitivo e existe como tipo nomeado, expandir
    if (!isPrimitivo && namedTypes[f.tipo]) {
      result += expandType(f.tipo, depth + 1, new Set(visited));
    }
  }

  return result;
}

// ── 5. Extrair operações do portType ──

const operations = [];
const ptBlocks = xml.match(/<[\w:]*portType[\s\S]*?<\/[\w:]*portType>/gi) || [];
for (const pt of ptBlocks) {
  const opRegex = /<[\w:]*operation\s+[^>]*?name\s*=\s*["']([^"']*)["']/gi;
  let opMatch;
  while ((opMatch = opRegex.exec(pt)) !== null) {
    operations.push(opMatch[1]);
  }
}

// ── 6. Extrair mensagens (para headers e faults) ──

const messages = {};
const msgRegex = /<[\w:]*message\s+[^>]*?name\s*=\s*["']([^"']*)["'][^>]*?>([\s\S]*?)<\/[\w:]*message>/gi;
let msgMatch;
while ((msgMatch = msgRegex.exec(xml)) !== null) {
  const msgName = msgMatch[1];
  const body = msgMatch[2];
  const parts = [];
  const partRegex = /<[\w:]*part\s+[^>]*?name\s*=\s*["']([^"']*)["'][^>]*?(?:element|type)\s*=\s*["']([^"']*)["'][^>]*?\/?>/gi;
  let pMatch;
  while ((pMatch = partRegex.exec(body)) !== null) {
    parts.push({ nome: pMatch[1], tipo: stripNs(pMatch[2]) });
  }
  messages[msgName] = parts;
}

// ── 7. Extrair soapAction do binding ──

const soapActions = {};
const bindOpRegex = /<[\w:]*operation\s+[^>]*?name\s*=\s*["']([^"']*?)["'][^>]*?>[\s\S]*?soapAction\s*=\s*["']([^"']*)["']/gi;
let bindMatch;
while ((bindMatch = bindOpRegex.exec(xml)) !== null) {
  soapActions[bindMatch[1]] = bindMatch[2];
}

// ── 8. Extrair endpoint ──

const endpointMatch = xml.match(/address\s+location\s*=\s*["']([^"']*)["']/i);
const endpoint = endpointMatch ? endpointMatch[1] : 'não encontrado';

// ── 9. Extrair simpleTypes / enums ──

const simpleTypes = [];
const stRegex = /<[\w:]*simpleType\s+[^>]*?name\s*=\s*["']([^"']*)["'][^>]*?>([\s\S]*?)<\/[\w:]*simpleType>/gi;
let stMatch;
while ((stMatch = stRegex.exec(xml)) !== null) {
  const stName = stMatch[1];
  const body = stMatch[2];
  const enumVals = [];
  const enumRegex = /value\s*=\s*["']([^"']*)["']/gi;
  let eMatch;
  while ((eMatch = enumRegex.exec(body)) !== null) {
    enumVals.push(eMatch[1]);
  }
  if (enumVals.length > 0) {
    simpleTypes.push({ nome: stName, valores: enumVals });
  }
}

// ── 10. Montar output ──

let out = `=== API: ${apiId} ===\n`;
out += `Endpoint: ${endpoint}\n\n`;

out += `OPERAÇÕES (${operations.length}):\n`;
out += `${'─'.repeat(50)}\n\n`;

for (const op of operations) {
  out += `▶ ${op}\n`;

  // SoapAction
  if (soapActions[op]) {
    out += `  SOAPAction: ${soapActions[op]}\n`;
  }

  // Headers
  const headerMsg = messages[`ServicoDeReintegracao_${op}_InputMessage_Headers`] || 
                    Object.entries(messages).find(([k]) => k.includes(op) && k.includes('Headers'))?.[1];
  if (headerMsg && headerMsg.length > 0) {
    out += `  Headers SOAP obrigatórios:\n`;
    for (const h of headerMsg) {
      out += `    - ${h.nome} (${h.tipo})\n`;
      if (namedTypes[h.tipo]) {
        out += expandType(h.tipo, 3, new Set());
      }
    }
  }

  // Input (elemento raiz + expansão)
  const inputEl = rootElements[op];
  out += `\n  ENTRADA (request body):\n`;
  out += `  Elemento raiz: <${op}>\n`;
  if (inputEl) {
    for (const campo of inputEl) {
      out += `    - ${campo.nome}: ${campo.tipo}${campo.obrigatorio ? ' [OBRIGATÓRIO]' : ' [opcional]'}\n`;
      if (namedTypes[campo.tipo]) {
        out += expandType(campo.tipo, 3, new Set());
      }
    }
  } else {
    out += `    (sem parâmetros diretos)\n`;
  }

  // Output (elemento raiz Response + expansão)
  const outputEl = rootElements[op + 'Response'];
  out += `\n  SAÍDA (response body):\n`;
  out += `  Elemento raiz: <${op}Response>\n`;
  if (outputEl) {
    for (const campo of outputEl) {
      out += `    - ${campo.nome}: ${campo.tipo}${campo.obrigatorio ? ' [OBRIGATÓRIO]' : ' [opcional]'}\n`;
      if (namedTypes[campo.tipo]) {
        out += expandType(campo.tipo, 3, new Set());
      }
    }
  } else {
    out += `    (sem campos de retorno detalhados)\n`;
  }

  // Faults
  const faultKeys = Object.keys(messages).filter(k => k.includes(op) && k.includes('Fault'));
  if (faultKeys.length > 0) {
    out += `\n  ERROS POSSÍVEIS (faults):\n`;
    for (const fk of faultKeys) {
      const faultName = fk.split('_').pop().replace('Message', '');
      out += `    - ${faultName}:\n`;
      for (const p of messages[fk]) {
        out += `      ${p.nome} (${p.tipo})\n`;
        if (namedTypes[p.tipo]) {
          const fields = resolveFields(p.tipo, new Set());
          for (const f of fields) {
            out += `        - ${f.nome}: ${f.tipo}\n`;
          }
        }
      }
    }
  }

  out += `\n${'─'.repeat(50)}\n\n`;
}

// Tipos simples / enums
if (simpleTypes.length > 0) {
  out += `ENUMS / TIPOS SIMPLES:\n`;
  for (const st of simpleTypes) {
    out += `  ◇ ${st.nome}: ${st.valores.join(', ')}\n`;
  }
  out += '\n';
}

return [{
  json: {
    api_id: apiId,
    conteudo: out
  }
}];
